const days = $.input.daysBack || 7;
const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000);
const y = since.getFullYear();
const m = String(since.getMonth() + 1).padStart(2, '0');
const d = String(since.getDate()).padStart(2, '0');
const afterDate = y + '/' + m + '/' + d;
const query = '(subject:application OR subject:interview OR subject:offer OR subject:"job" OR subject:"position" OR subject:"role" OR subject:"hiring" OR subject:"recruiter" OR from:linkedin OR from:indeed OR from:greenhouse OR from:lever OR from:workday) after:' + afterDate;
return { query, afterDate, daysBack: days };

const response = $.steps.searchEmails.response;
const messages = response.messages || response.data || [];
let compiled = '';
let count = 0;

if (Array.isArray(messages)) {
  messages.slice(0, 40).forEach((msg, i) => {
    const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
    const getH = (n) => { const h = headers.find(h => h.name && h.name.toLowerCase() === n.toLowerCase()); return h ? h.value : ''; };
    compiled += 'Email #' + (i + 1) + ':\n';
    compiled += '  From: ' + (getH('From') || msg.from || 'Unknown') + '\n';
    compiled += '  To: ' + (getH('To') || msg.to || '') + '\n';
    compiled += '  Subject: ' + (getH('Subject') || msg.subject || '(no subject)') + '\n';
    compiled += '  Date: ' + (getH('Date') || msg.date || '') + '\n';
    compiled += '  Body Preview: ' + (msg.snippet || msg.body || '').slice(0, 400) + '\n\n';
    count++;
  });
}

return { compiled, emailCount: count };

const data = $.steps.compileEmails.output;

let prompt = 'You are a job application tracking assistant. Analyze the following ' + data.emailCount + ' emails and extract job application data.\n\n';
prompt += 'EMAILS:\n' + data.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract ONLY emails genuinely related to job applications, interviews, offers, or recruitment\n';
prompt += '- For each job-related email, extract: company name, job title/role, application status, contact person, date, and any next steps\n';
prompt += '- Status should be one of: Applied, Phone Screen, Interview Scheduled, Interview Completed, Offer, Rejected, Follow-Up Needed, Informational\n';
prompt += '- Skip promotional emails, newsletters, and spam even if they mention jobs\n';
prompt += '- Deduplicate: if multiple emails are about the same company/role, merge into one entry with latest status\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "applications": [\n';
prompt += '    {\n';
prompt += '      "company": "Company Name",\n';
prompt += '      "role": "Job Title",\n';
prompt += '      "status": "Applied|Phone Screen|Interview Scheduled|Interview Completed|Offer|Rejected|Follow-Up Needed",\n';
prompt += '      "contactPerson": "recruiter or hiring manager name",\n';
prompt += '      "contactEmail": "their email",\n';
prompt += '      "dateReceived": "YYYY-MM-DD",\n';
prompt += '      "nextSteps": "what to do next",\n';
prompt += '      "notes": "any additional context"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "summary": "overview of application pipeline",\n';
prompt += '  "totalFound": 0\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { applications: [], summary: raw, totalFound: 0 }; }

const ai = $.steps.parseAI.output;
const apps = ai.applications || [];
const today = new Date().toISOString().split('T')[0];

const headerRow = ['Company', 'Role', 'Status', 'Contact Person', 'Contact Email', 'Date Received', 'Next Steps', 'Notes', 'Last Updated'];
const rows = [headerRow];

apps.forEach(app => {
  rows.push([
    app.company || '',
    app.role || '',
    app.status || 'Unknown',
    app.contactPerson || '',
    app.contactEmail || '',
    app.dateReceived || '',
    app.nextSteps || '',
    app.notes || '',
    today
  ]);
});

return { rows, applicationCount: apps.length, summary: ai.summary || '' };
